410	func TestAllEcosystemDomainFunctions(t *testing.T) {
411		// Test that all ecosystem categories return non-empty slices
412		ecosystemCategories := []string{
413			"defaults", "containers", "bazel", "dotnet", "dart", "github", "go",
414			"terraform", "haskell", "java", "julia", "kotlin", "linux-distros", "lua", "node",
415			"ocaml", "perl", "php", "playwright", "python", "r", "ruby", "rust", "swift",
416		}
417	
418		for _, category := range ecosystemCategories {
419			t.Run("getEcosystemDomains_"+category, func(t *testing.T) {
420				domains := getEcosystemDomains(category)
421				if len(domains) == 0 {
422					t.Errorf("getEcosystemDomains(%q) returned empty slice, expected at least one domain", category)
423				}
424	
425				// Check that all domains are non-empty strings
426				for i, domain := range domains {
427					if domain == "" {
428						t.Errorf("getEcosystemDomains(%q) returned empty domain at index %d", category, i)
429					}
430				}
431			})
432		}
433	}
434	
435	func TestEcosystemDomainsUniqueness(t *testing.T) {
436		// Test that each ecosystem category returns unique domains (no duplicates)
437		ecosystemCategories := []string{
438			"defaults", "containers", "bazel", "dotnet", "dart", "github", "go",
439			"terraform", "haskell", "java", "julia", "kotlin", "linux-distros", "lua", "node",
440			"ocaml", "perl", "php", "playwright", "python", "r", "ruby", "rust", "swift",
441		}
442	
443		for _, category := range ecosystemCategories {
444			t.Run("getEcosystemDomains_"+category+"_uniqueness", func(t *testing.T) {
445				domains := getEcosystemDomains(category)
446				seen := make(map[string]bool)
447	
448				for _, domain := range domains {
449					if seen[domain] {
450						t.Errorf("getEcosystemDomains(%q) returned duplicate domain: %s", category, domain)
451					}
452					seen[domain] = true
453				}
454			})
455		}
456	}
