			"archive.apache.org",
			"download.java.net",
			"api.foojay.io",
			"cdn.azul.com",
			"central.sonatype.com",
			"maven.google.com",
			"dl.google.com",
			"repo.gradle.org",
		}

		for _, expectedDomain := range expectedDomains {
